exec("""from __future__ import annotations\nimport csv, json, os, time\nfrom dataclasses import asdict, dataclass\nfrom datetime import datetime, timedelta, timezone\nfrom pathlib import Path\nfrom urllib.parse import quote_plus\nimport requests\nfrom src.product_matcher import triple_check_product\nROOT = Path(__file__).resolve().parents[1]; CONFIG_DIR = ROOT / 'config'; OUTPUT_DIR = ROOT / 'output'; JST = timezone(timedelta(hours=9), 'JST')\nREQUEST_TIMEOUT_SEC = int(os.getenv('REQUEST_TIMEOUT_SEC','25')); RAKUTEN_HITS = int(os.getenv('RAKUTEN_HITS','5')); RAKUTEN_MAX_PRODUCTS = int(os.getenv('RAKUTEN_MAX_PRODUCTS','30'))\n@dataclass(frozen=True)\nclass SupplierOffer:\n    jan: str; supplier: str; supplier_product_name: str; url: str; supplier_price_yen: int | None; stock_status: str; condition: str; image_url: str; source_type: str; fetched_at_jst: str\n@dataclass(frozen=True)\nclass Opportunity:\n    jan: str; product_name: str; category: str; enoking_buy_price_yen: int; supplier: str; supplier_product_name: str; supplier_url: str; supplier_price_yen: int | None; gross_gap_yen: int | None; stock_status: str; condition: str; match_status: str; match_score: int; triple_check_done: bool; jan_exact: bool; title_model_match: bool; variant_safe: bool; warning: str; source_type: str; search_links: dict; fetched_at_jst: str\ndef to_int(v):\n    s = ''.join(ch for ch in str(v or '') if ch.isdigit()); return int(s) if s else None\ndef build_search_links(p):\n    jan = str(p.get('jan') or ''); name = str(p.get('product_name') or ''); q = quote_plus(jan or name); nq = quote_plus(name)\n    return {'Google Shopping': f'https://www.google.com/search?tbm=shop&q={q}', 'Rakuten': f'https://search.rakuten.co.jp/search/mall/{q}/', 'Yahoo Shopping': f'https://shopping.yahoo.co.jp/search?p={q}', 'Amazon JP': f'https://www.amazon.co.jp/s?k={q}', 'Google Name': f'https://www.google.com/search?tbm=shop&q={nq}'}\ndef read_supplier_candidates(path: Path = CONFIG_DIR / 'supplier_candidates.csv'):\n    if not path.exists(): return []\n    out=[]; now=datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z')\n    with path.open('r', encoding='utf-8-sig', newline='') as f:\n        for r in csv.DictReader(f):\n            if r.get('jan') and r.get('url'):\n                out.append(SupplierOffer(r.get('jan','').strip(), r.get('supplier','manual') or 'manual', r.get('supplier_product_name') or r.get('product_name') or '', r.get('url',''), to_int(r.get('supplier_price_yen')), r.get('stock_status','manual_check'), r.get('condition','new'), r.get('image_url',''), 'manual_csv', now))\n    return out\ndef rakuten_api_offers(products):\n    app = os.getenv('RAKUTEN_APPLICATION_ID','').strip()\n    if not app: return []\n    out=[]; now=datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z'); s=requests.Session(); ep='https://app.rakuten.co.jp/services/api/IchibaItem/Search/20220601'\n    for p in products[:RAKUTEN_MAX_PRODUCTS]:\n        kw=str(p.get('jan') or p.get('product_name') or '')\n        if not kw: continue\n        try:\n            res=s.get(ep, params={'format':'json','applicationId':app,'keyword':kw,'hits':RAKUTEN_HITS,'sort':'+itemPrice'}, timeout=REQUEST_TIMEOUT_SEC)\n            if res.status_code >= 400: continue\n            for w in res.json().get('Items', []):\n                item=w.get('Item', {}); imgs=item.get('mediumImageUrls') or []; img=imgs[0].get('imageUrl','') if imgs else ''\n                out.append(SupplierOffer(str(p.get('jan') or ''), 'Rakuten Ichiba API', item.get('itemName',''), item.get('itemUrl',''), to_int(item.get('itemPrice')), 'api_result_manual_stock_check', 'new_or_unknown', img, 'rakuten_api', now))\n            time.sleep(1)\n        except Exception:\n            continue\n    return out\ndef _search_only(p):\n    now=datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z'); return Opportunity(str(p.get('jan') or ''), str(p.get('product_name') or ''), str(p.get('category') or ''), to_int(p.get('buy_price_yen')) or 0, '検索リンク', '', '', None, None, 'search_links_only', 'manual_check_required', 'NOT_CHECKED_SEARCH_ONLY', 0, False, False, False, False, '仕入れ先候補URLを開き、JAN/名称/色/容量を確認してください。', 'generated_search_links', build_search_links(p), now)\ndef _offer_to_opportunity(p, offer):\n    chk=triple_check_product(p, asdict(offer)); buy=to_int(p.get('buy_price_yen')) or 0; gap=buy-offer.supplier_price_yen if offer.supplier_price_yen is not None else None\n    return Opportunity(str(p.get('jan') or ''), str(p.get('product_name') or ''), str(p.get('category') or ''), buy, offer.supplier, offer.supplier_product_name, offer.url, offer.supplier_price_yen, gap, offer.stock_status, offer.condition, chk.status, chk.score, True, chk.jan_exact, chk.title_model_match, chk.variant_safe, chk.warning, offer.source_type, build_search_links(p), offer.fetched_at_jst)\ndef generate_opportunities(products, offers=None):\n    by_jan={str(p.get('jan') or ''):p for p in products}; all_offers=list(offers or [])+read_supplier_candidates()+rakuten_api_offers(products); out=[]; used=set()\n    for o in all_offers:\n        p=by_jan.get(o.jan)\n        if p: out.append(_offer_to_opportunity(p,o)); used.add(o.jan)\n    for p in products:\n        if str(p.get('jan') or '') not in used: out.append(_search_only(p))\n    return sorted(out, key=lambda x: (x.gross_gap_yen is None, -(x.gross_gap_yen or -10**9), x.product_name))\ndef write_opportunities(opportunities, output_dir: Path = OUTPUT_DIR):\n    output_dir.mkdir(parents=True, exist_ok=True); stamp=datetime.now(JST).strftime('%Y%m%d_%H%M%S'); rows=[asdict(o) for o in opportunities]; paths={'json':output_dir/f'opportunities_{stamp}.json','csv':output_dir/f'opportunities_{stamp}.csv','latest_json':output_dir/'latest_opportunities.json','latest_csv':output_dir/'latest_opportunities.csv'}\n    for p in [paths['json'], paths['latest_json']]: p.write_text(json.dumps(rows, ensure_ascii=False, indent=2), encoding='utf-8')\n    fields=list(rows[0].keys()) if rows else ['message']\n    for p in [paths['csv'], paths['latest_csv']]:\n        with p.open('w', encoding='utf-8-sig', newline='') as f:\n            w=csv.DictWriter(f, fieldnames=fields); w.writeheader(); w.writerows(rows or [{'message':'NO_OPPORTUNITIES'}])\n    return {k:str(v) for k,v in paths.items()}\n""")